import { GoogleGenAI, Modality, GenerateContentResponse } from "@google/genai";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Helper for decoding PCM audio from Gemini
export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const generateTTS = async (
  text: string, 
  voiceName: string = 'Kore',
  emotion: string = 'Neutral'
) => {
  const ai = getAIClient();
  const prompt = `Say in a ${emotion} tone: ${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  return base64Audio;
};

export const generatePodcastScript = async (
  source: string, 
  type: 'text' | 'url' | 'pdf', 
  mode: 'interview' | 'monologue' = 'interview'
) => {
  const ai = getAIClient();
  const systemInstruction = `
    Act as a Senior Podcast Producer and Fact-Checking Expert for DuviPod Pro.
    Your goal is to create a professional podcast script based on the provided content.
    - Fact-Checking: Verify data using your internal knowledge and grounding.
    - If a fact is uncertain, insert "[Fuente pendiente de confirmación]".
    - Neutrality: Keep an objective tone.
    - Conversation: Create a ${mode} script.
    - Annotations: Insert emotional markers like [Alegre], [Triste] based on context.
    - Sources: List high-reputation sources at the end.
    - Output should be structured for a podcast.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: source,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
    },
  });

  return {
    text: response.text || "Failed to generate script.",
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
  };
};

export const translateText = async (text: string, targetLang: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following text to ${targetLang}: ${text}`,
  });
  return response.text;
};

