import React, { useState } from 'react';
import { translateText } from '../services/gemini';

interface EditorProps {
  text: string;
  setText: (text: string) => void;
  onGenerate: () => void;
  isGenerating: boolean;
  theme: string;
}

const Editor: React.FC<EditorProps> = ({ text, setText, onGenerate, isGenerating, theme }) => {
  const [translating, setTranslating] = useState(false);

  const insertTag = (tag: string) => {
    setText(text + ` [${tag}] `);
  };

  const handleTranslate = async () => {
    if (!text) return;
    setTranslating(true);
    try {
      const translated = await translateText(text, 'English');
      if (translated) setText(translated);
    } finally {
      setTranslating(false);
    }
  };

  return (
    <div className="bg-white dark:bg-zinc-900 rounded-3xl p-6 shadow-xl border border-gray-200 dark:border-gray-800 flex flex-col gap-4">
      {/* Quick Actions */}
      <div className="flex flex-wrap gap-2 pb-4 border-b border-gray-100 dark:border-zinc-800">
        <span className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center mr-2">Pausas</span>
        {['1s', '2s', '3s', '4s'].map(p => (
          <button key={p} onClick={() => insertTag(`Pausa ${p}`)} className="px-3 py-1.5 rounded-full bg-gray-100 dark:bg-zinc-800 text-sm hover:bg-gray-200 transition-colors">
            {p}
          </button>
        ))}
        <div className="w-px h-6 bg-gray-200 dark:bg-zinc-800 mx-2" />
        <span className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center mr-2">Efectos</span>
        {['Risa', 'Llanto', 'Suspiro', 'Tos'].map(e => (
          <button key={e} onClick={() => insertTag(e)} className="px-3 py-1.5 rounded-full bg-gray-100 dark:bg-zinc-800 text-sm hover:bg-gray-200 transition-colors">
            {e}
          </button>
        ))}
      </div>

      {/* Main Textarea */}
      <textarea
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Escribe el texto que quieres convertir a voz aquí..."
        className="w-full h-80 bg-transparent resize-none text-lg focus:outline-none placeholder-gray-300 dark:placeholder-gray-700"
      />

      {/* Footer Actions */}
      <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-zinc-800">
        <div className="flex gap-2">
          <button
            onClick={handleTranslate}
            disabled={translating}
            className="flex items-center gap-2 px-4 py-2 rounded-xl border border-gray-200 dark:border-zinc-800 hover:bg-gray-50 dark:hover:bg-zinc-800 transition-all text-sm"
          >
            {translating ? 'Traduciendo...' : 'Traducir Auto'}
          </button>
          <label className="flex items-center gap-2 px-4 py-2 rounded-xl border border-gray-200 dark:border-zinc-800 hover:bg-gray-50 dark:hover:bg-zinc-800 transition-all text-sm cursor-pointer">
            <span>Subir Doc</span>
            <input type="file" className="hidden" accept=".txt,.pdf" />
          </label>
        </div>

        <button
          onClick={onGenerate}
          disabled={isGenerating || !text}
          className={`px-8 py-3 rounded-2xl bg-gradient-to-r ${theme} text-white font-bold shadow-lg shadow-indigo-500/20 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100`}
        >
          {isGenerating ? 'Generando...' : 'Generar Audio'}
        </button>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useEffect, useRef } from 'react';

interface AudioPlayerProps {
  base64Data: string | null;
}

const AudioPlayer: React.FC<AudioPlayerProps> = ({ base64Data }) => {
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  useEffect(() => {
    if (base64Data) {
      const blob = new Blob([new Uint8Array(atob(base64Data).split("").map(c => c.charCodeAt(0)))], { type: 'audio/pcm' });
      // Note: PCM needs a wrapper to play in HTML5, but for simplicity we convert to a data URL if it was a standard format
      // In this specific Gemini TTS example, we play via Web Audio API in the service, 
      // but here is a simple container for playback tracking.
      setAudioUrl(`data:audio/wav;base64,${base64Data}`);
    }
  }, [base64Data]);

  if (!base64Data) return null;

  return (
    <div className="mt-6 p-4 rounded-2xl bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800/50 flex items-center gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="h-12 w-12 rounded-full bg-indigo-500 flex items-center justify-center text-white">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
      </div>
      <div className="flex-1">
        <p className="text-sm font-medium text-indigo-900 dark:text-indigo-100">Audio Generado con Éxito</p>
        <div className="mt-2 h-1.5 bg-indigo-200 dark:bg-indigo-800 rounded-full overflow-hidden">
          <div className="h-full bg-indigo-500 w-1/3 rounded-full" />
        </div>
      </div>
      <button className="px-4 py-2 rounded-xl bg-white dark:bg-zinc-800 text-sm font-bold shadow-sm hover:shadow-md transition-all">
        Descargar MP3
      </button>
    </div>
  );
};

