interface EditorProps {
  text: string;
  setText: (text: string) => void;
  onGenerate: () => void;
  isGenerating: boolean;
  theme: string;
  mode: 'vox' | 'pod';
}

const Editor: React.FC<EditorProps> = ({ text, setText, onGenerate, isGenerating, theme, mode }) => {
  const [loading, setLoading] = useState(false);
  const [socialUrl, setSocialUrl] = useState('');

  const insertTag = (tag: string) => {
    setText(text + ` [${tag}] `);
  };

  const handleTranslate = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const translated = await translateText(text, 'English');
      if (translated) setText(translated);
    } finally {
      setLoading(false);
    }
  };

  const handleFactCheck = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const refined = await factCheckAndRefine(text);
      if (refined) setText(refined);
    } finally {
      setLoading(false);
    }
  };

  const handleSocialImport = async () => {
    if (!socialUrl) return;
    setLoading(true);
    try {
      const script = await analyzeSocialUrl(socialUrl);
      if (script) {
        setText(script);
        setSocialUrl('');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white dark:bg-slate-900/50 rounded-[2.5rem] p-8 shadow-2xl border border-white dark:border-white/5 flex flex-col gap-6 backdrop-blur-xl">
