  const [pitch, setPitch] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [lastAudio, setLastAudio] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('duvivox_state', JSON.stringify(state));
  }, [state]);

  const handleGenerate = async () => {
    if (!text) return;
    setIsGenerating(true);
    try {
      const voice = VOICE_DATA[state.language].voices.find(v => v.id === selectedVoice);
      // Use voice?.id here because the ID now corresponds to a valid Gemini prebuilt voice name (Kore, Zephyr, etc.)
      const base64 = await generateTTS(text, voice?.id || 'Kore', selectedEmotion, speed, pitch);
      if (base64) {
        setLastAudio(base64);

        const newItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          text: text.slice(0, 50) + '...',
          timestamp: Date.now(),
          audioData: base64,
          voice: voice?.name || 'Unknown',
          lang: state.language
        };

        setState(prev => ({
          ...prev,
          history: [newItem, ...prev.history].slice(0, 50)
        }));

        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.start();
      }
    } catch (error) {
      console.error("Master Production failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className={state.isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-[#f8fafc] dark:bg-[#020617] transition-all duration-700">
        <TopBar state={state} setState={setState} />

