import React, { useState } from 'react';
import { generateTTS, decode, decodeAudioData } from '../services/gemini';

interface VoicePreviewProps {
  voiceId: string;
  voiceName: string;
  theme: string;
}

const VoicePreview: React.FC<VoicePreviewProps> = ({ voiceId, voiceName, theme }) => {
  const [isPlaying, setIsPlaying] = useState(false);

  const handlePreview = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isPlaying) return;
    setIsPlaying(true);
    try {
      // Short preview phrase
      // Use voiceId here because the ID now corresponds to a valid Gemini prebuilt voice name (Kore, Zephyr, etc.)
      const base64 = await generateTTS(`Hola, soy ${voiceName}, tu voz de DuviVox.`, voiceId, 'Alegre');
      if (base64) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.onended = () => setIsPlaying(false);
        source.start();
      } else {
        setIsPlaying(false);
      }
    } catch {
      setIsPlaying(false);
    }
  };

  return (
    <button
      onClick={handlePreview}
      className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${isPlaying ? `bg-gradient-to-r ${theme} scale-110` : 'bg-white/10 hover:bg-white/20'}`}
      title="Vista previa de voz"
    >
      {isPlaying ? (
        <div className="flex gap-0.5 items-end h-3">
          <div className="w-0.5 h-full bg-white animate-pulse" />
          <div className="w-0.5 h-1/2 bg-white animate-pulse" />
          <div className="w-0.5 h-full bg-white animate-pulse" />
        </div>
      ) : (
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="currentColor" viewBox="0 0 20 20">
          <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168l4.2 2.8a1 1 0 010 1.664l-4.2 2.8A1 1 0 018 13.604V7.996a1 1 0 011.555-.832z" />
        </svg>
      )}
    </button>
  );
};

