import React, { useState, useEffect } from 'react';

interface OnboardingProps {
  onClose: () => void;
  theme: string;
}

const Onboarding: React.FC<OnboardingProps> = ({ onClose, theme }) => {
  const [step, setStep] = useState(0);
  const [displayText, setDisplayText] = useState('');

  const screens = [
    {
      title: "🚀 DuviVox Studio",
      text: "¡Bienvenido a la nueva era de la voz! Has ingresado a DuviVox Studio, donde tus ideas dejan de ser texto para convertirse en experiencias sonoras de alta fidelidad.",
      quote: "Tu voz no tiene fronteras, y ahora, tu tecnología tampoco."
    },
    {
      title: "🎭 Poder de la Diversidad",
      text: "Global: Salta entre 4 idiomas y 19 dialectos únicos. Emocional: No solo hablamos, sentimos. Humano: Inserta risas y pausas naturales."
    },
    {
      title: "✅ Compromiso con la Verdad",
      text: "Crea con confianza. Gracias a nuestra integración con Google Search, puedes verificar datos en tiempo real antes de generar tu audio."
    },
    {
      title: "🛠️ Tu Espacio, Tus Reglas",
      text: "Productividad Pomodoro, Estética personalizada y 20 Paisajes Sonoros para envolver tu voz en una atmósfera única."
    }
  ];

  useEffect(() => {
    let i = 0;
    const fullText = screens[step].text;
    setDisplayText('');
    const interval = setInterval(() => {
      setDisplayText(fullText.slice(0, i));
      i++;
      if (i > fullText.length) clearInterval(interval);
    }, 20);
    return () => clearInterval(interval);
  }, [step]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-500">
      <div className="max-w-2xl w-full bg-white dark:bg-slate-900 rounded-[3rem] p-10 shadow-2xl border border-white/20 relative overflow-hidden">
        {/* Animated Background Pulse */}
        <div className={`absolute -top-24 -right-24 w-64 h-64 bg-gradient-to-br ${theme} opacity-20 blur-3xl rounded-full sonic-logo`} />

        <div className="relative z-10 flex flex-col items-center text-center">
          <div className={`h-20 w-20 rounded-3xl bg-gradient-to-br ${theme} flex items-center justify-center shadow-2xl mb-8 sonic-logo`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>

          <h2 className="text-4xl font-black tracking-tighter mb-4 shimmer-text">{screens[step].title}</h2>
          <p className="text-lg text-slate-600 dark:text-slate-300 font-medium leading-relaxed min-h-[80px]">
            {displayText}
          </p>

          {screens[step].quote && (
            <p className="mt-4 italic text-indigo-500 font-bold">"{screens[step].quote}"</p>
          )}

          <div className="flex gap-2 mt-10">
            {screens.map((_, i) => (
              <div key={i} className={`h-1.5 rounded-full transition-all duration-300 ${i === step ? 'w-8 bg-indigo-500' : 'w-2 bg-slate-200 dark:bg-slate-800'}`} />
            ))}
          </div>

          <div className="flex gap-4 mt-8 w-full">
            {step > 0 && (
              <button onClick={() => setStep(s => s - 1)} className="flex-1 py-4 rounded-2xl bg-slate-100 dark:bg-white/5 font-bold hover:bg-slate-200 transition-all">Anterior</button>
            )}
            {step < screens.length - 1 ? (
              <button onClick={() => setStep(s => s + 1)} className={`flex-[2] py-4 rounded-2xl bg-gradient-to-r ${theme} text-white font-black uppercase tracking-widest shadow-xl hover:scale-105 transition-all`}>Continuar</button>
            ) : (
              <button onClick={onClose} className={`flex-[2] py-4 rounded-2xl bg-gradient-to-r ${theme} text-white font-black uppercase tracking-widest shadow-xl hover:scale-105 transition-all animate-pulse`}>EMPEZAR A CREAR</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
