import { GoogleGenAI, Modality, GenerateContentResponse } from "@google/genai";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Token Tracker Logic
export const trackUsage = (tokens: number) => {
  const history = JSON.parse(localStorage.getItem('duvivox_usage') || '[]');
  const today = new Date().toISOString().split('T')[0];
  const existing = history.find((u: any) => u.date === today);
  if (existing) {
    existing.tokens += tokens;
  } else {
    history.push({ date: today, tokens });
  }
  localStorage.setItem('duvivox_usage', JSON.stringify(history));
};

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const generateTTS = async (
  text: string, 
  voiceName: string = 'Kore',
  emotion: string = 'Neutral',
  speed: number = 1.0,
  pitch: number = 0
) => {
  const ai = getAIClient();
  const prompt = `System: You are an expert voice actor. 
    Mood: ${emotion}
    Style: Speech speed ${speed}x, pitch shift ${pitch}.
    Content: ${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });

  // Rough estimate of tokens
  trackUsage(text.length / 3);

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  return base64Audio;
};

export const factCheckAndRefine = async (text: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Fact-check the following text and refine it for professional podcast production. If something is unverified, tag it with [Fuente pendiente]. Text: ${text}`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });
  return response.text;
};

export const analyzeSocialUrl = async (url: string, durationSeconds: number) => {
  const ai = getAIClient();
  const isLong = durationSeconds > 120;

  const systemInstruction = `
    Actúa como un Productor Senior de Podcast. Tu objetivo es transformar contenido de redes sociales en un guion profesional.
    - Duración objetivo: ${durationSeconds} segundos.
    - Si la duración es mayor a 2 minutos (>120s), DEBES investigar a fondo la historia y contexto del tema usando Google Search para expandir el guion de forma educativa y entretenida.
    - Si no encuentras información adicional, sugiere un guion creativo de extensión basado en el tema.
    - Incluye marcadores de [Risa], [Pausa], [stress] según corresponda.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analiza esta URL y crea un podcast de aproximadamente ${durationSeconds} segundos: ${url}`,
    config: {
      systemInstruction,
      tools: isLong ? [{ googleSearch: {} }] : [],
    },
  });
  return response.text;
