  // Enhanced logic to handle custom tags parsing [Voz], [stress], [BG], [Fact-Check]
  const processTextTags = useCallback(async (rawText: string) => {
    let processedText = rawText;
    let localVoice = selectedVoice;
    let localSpeed = speed;

    // 1. Check for [Fact-Check] tag anywhere
    if (processedText.includes('[Fact-Check]')) {
      const refined = await factCheckAndRefine(processedText.replace('[Fact-Check]', ''));
      if (refined) processedText = refined;
    }

    // 2. [Voz: ID] tag - instant voice switch for the whole segment
    const voiceMatch = processedText.match(/\[Voz:\s*([^\]]+)\]/);
    if (voiceMatch) {
      const nameOrId = voiceMatch[1].trim();
      const vFound = Object.values(VOICE_DATA).flatMap(l => l.voices).find(v => 
        v.name.toLowerCase() === nameOrId.toLowerCase() || v.id.toLowerCase() === nameOrId.toLowerCase()
      );
      if (vFound) localVoice = vFound.id;
      processedText = processedText.replace(voiceMatch[0], '');
    }

    // 3. [stress] tag - handled by instructions but explicitly marked for TTS engine
    if (processedText.includes('[stress]')) {
      // In the prompt sent to Gemini TTS, we instruct to treat this as increased volume and slower speed (-5%)
      processedText = processedText.replace(/\[stress\](.*?)\[\/stress\]/g, ' [ENFATIZAR: $1] ');
      processedText = processedText.replace(/\[stress\]/g, ' [EMPEZAR ENFASIS] ');
    }

    // 4. [BG: Name] - Background Sound Placeholder
    // Note: Actual mixer mixing would happen in post-processing, 
    // but here we ensure the parser acknowledges it.
    const bgMatch = processedText.match(/\[BG:\s*([^\]]+)\]/);
    if (bgMatch) {
       console.log(`Setting background ambiance to: ${bgMatch[1]}`);
       processedText = processedText.replace(bgMatch[0], '');
    }

    // 5. [Pausa Xs] - handled naturally by punctuation in Gemini usually, 
    // but we can normalize it for the engine
    processedText = processedText.replace(/\[Pausa\s*(\d+)s\]/gi, (match, sec) => ` [Pausa de ${sec} segundos] `);

    return { text: processedText, voiceId: localVoice, speed: localSpeed };
  }, [selectedVoice, speed]);

  const handleGenerate = async () => {
    if (!text) return;
    setIsGenerating(true);
    try {
      const { text: cleanText, voiceId, speed: finalSpeed } = await processTextTags(text);
      const voice = Object.values(VOICE_DATA).flatMap(l => l.voices).find(v => v.id === voiceId);

      const base64 = await generateTTS(cleanText, voice?.id || 'Kore', selectedEmotion, finalSpeed, pitch);
