import { GoogleGenAI, Modality, GenerateContentResponse } from "@google/genai";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Token Tracker Logic
export const trackUsage = (tokens: number) => {
  const history = JSON.parse(localStorage.getItem('duvivox_usage') || '[]');
  const today = new Date().toISOString().split('T')[0];
  const existing = history.find((u: any) => u.date === today);
  if (existing) {
    existing.tokens += tokens;
  } else {
    history.push({ date: today, tokens });
  }
  localStorage.setItem('duvivox_usage', JSON.stringify(history));
};

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

