export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { AppState, Language, HistoryItem } from './types';
import { VOICE_DATA, EMOTIONAL_STATES, AMBIENT_SOUNDS, THEMES } from './constants';
import TopBar from './components/TopBar';
import Editor from './components/Editor';
import AudioPlayer from './components/AudioPlayer';
import VoicePreview from './components/VoicePreview';
import Onboarding from './components/Onboarding';
import UserGuide from './components/UserGuide';
import { generateTTS, decode, decodeAudioData, factCheckAndRefine } from './services/gemini';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('duvivox_state');
    const initial = saved ? JSON.parse(saved) : {
      language: 'ES',
      theme: 'from-slate-900 to-indigo-950 text-white',
      isDarkMode: true,
      activeTab: 'vox',
      history: [],
      usage: [],
      showOnboarding: true,
      showGuide: false
    };
    return initial;
  });

  const [text, setText] = useState('');
  const [selectedDialect, setSelectedDialect] = useState(VOICE_DATA[state.language].dialects[0]);
  const [selectedVoice, setSelectedVoice] = useState(VOICE_DATA[state.language].voices[0].id);
  const [selectedEmotion, setSelectedEmotion] = useState('Profesional');
  const [speed, setSpeed] = useState(1.0);
  const [pitch, setPitch] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [lastAudio, setLastAudio] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('duvivox_state', JSON.stringify(state));
  }, [state]);

  const playElegantOpening = () => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(440, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

    gain.gain.setValueAtTime(0, ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 0.1);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.8);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.8);
  };

  const processTextTags = useCallback(async (rawText: string) => {
    let processedText = rawText;
    let localVoice = selectedVoice;
    let localSpeed = speed;

    if (processedText.includes('[Fact-Check]')) {
      const refined = await factCheckAndRefine(processedText.replace('[Fact-Check]', ''));
      if (refined) processedText = refined;
    }

    const voiceMatch = processedText.match(/\[Voz:\s*([^\]]+)\]/);
    if (voiceMatch) {
      const nameOrId = voiceMatch[1].trim();
      const vFound = Object.values(VOICE_DATA).flatMap(l => l.voices).find(v => 
        v.name.toLowerCase() === nameOrId.toLowerCase() || v.id.toLowerCase() === nameOrId.toLowerCase()
      );
      if (vFound) localVoice = vFound.id;
      processedText = processedText.replace(voiceMatch[0], '');
    }

    if (processedText.includes('[stress]')) {
      processedText = processedText.replace(/\[stress\](.*?)\[\/stress\]/g, ' [ENFATIZAR: $1] ');
      processedText = processedText.replace(/\[stress\]/g, ' [EMPEZAR ENFASIS] ');
    }

    const bgMatch = processedText.match(/\[BG:\s*([^\]]+)\]/);
    if (bgMatch) {
       console.log(`Setting background ambiance to: ${bgMatch[1]}`);
       processedText = processedText.replace(bgMatch[0], '');
    }

    processedText = processedText.replace(/\[Pausa\s*(\d+)s\]/gi, (match, sec) => ` [Pausa de ${sec} segundos] `);

    return { text: processedText, voiceId: localVoice, speed: localSpeed };
  }, [selectedVoice, speed]);

  const handleGenerate = async () => {
    if (!text) return;
    setIsGenerating(true);
    try {
      const { text: cleanText, voiceId, speed: finalSpeed } = await processTextTags(text);
      const voice = Object.values(VOICE_DATA).flatMap(l => l.voices).find(v => v.id === voiceId);

      const base64 = await generateTTS(cleanText, voice?.id || 'Kore', selectedEmotion, finalSpeed, pitch);
      if (base64) {
        setLastAudio(base64);

        const newItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          text: cleanText.slice(0, 50) + '...',
          timestamp: Date.now(),
          audioData: base64,
          voice: voice?.name || 'Unknown',
          lang: state.language
        };

        setState(prev => ({
          ...prev,
          history: [newItem, ...prev.history].slice(0, 50)
        }));

        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.start();
      }
    } catch (error) {
      console.error("Master Production failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className={state.isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-[#f8fafc] dark:bg-[#020617] transition-all duration-700">
        <TopBar state={state} setState={setState} />

        {/* DUVI POD PRO HERO ACTIVATION - MOVED TO TOP */}
        <div className="max-w-7xl mx-auto px-6 md:px-10 pt-8">
          <div className="relative group p-1">
            <div className="absolute -inset-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-rose-500 rounded-[2.5rem] blur opacity-15 group-hover:opacity-60 transition duration-1000 group-hover:duration-200 animate-pulse"></div>
            <button 
              onClick={() => {
                playElegantOpening();
                setState(prev => ({ ...prev, activeTab: 'pod' }));
              }}
              className={`relative w-full py-8 rounded-[2.2rem] flex flex-col items-center justify-center gap-2 overflow-hidden bg-white dark:bg-slate-900 border border-white/20 dark:border-white/5 transition-all shadow-2xl group ${state.activeTab === 'pod' ? 'ring-2 ring-indigo-500 ring-offset-4 dark:ring-offset-slate-900 scale-[1.01]' : 'hover:scale-[1.005]'}`}
            >
              <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
              <div className="flex items-center gap-6">
                <div className="h-14 w-14 rounded-2xl bg-indigo-600 flex items-center justify-center text-white shadow-xl animate-bounce duration-[4000ms]">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                  </svg>
                </div>
                <div className="text-left">
                  <h4 className="text-3xl font-black tracking-tighter shimmer-text">Activar DuviPod Pro</h4>
                  <p className="text-xs font-bold text-indigo-500 uppercase tracking-[0.3em]">IA Master Scripting & Investigación Activa</p>
                </div>
              </div>
              <div className="mt-4 h-1.5 w-64 bg-slate-100 dark:bg-white/5 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 animate-shimmer w-full bg-[length:200%_100%] bg-gradient-to-r from-transparent via-white/40 to-transparent" />
              </div>
            </button>
          </div>
        </div>

        <button 
          onClick={() => setState(s => ({ ...s, showGuide: true }))}
          className="fixed bottom-10 right-10 z-[80] w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 transition-all group"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </button>

        {state.showOnboarding && <Onboarding theme={state.theme} onClose={() => setState(s => ({ ...s, showOnboarding: false }))} />}
        {state.showGuide && <UserGuide theme={state.theme} onClose={() => setState(s => ({ ...s, showGuide: false }))} />}

        <main className="max-w-7xl mx-auto p-6 md:p-10 flex flex-col lg:flex-row gap-10">
          <div className="flex-1 flex flex-col gap-8">
            {(state.activeTab === 'vox' || state.activeTab === 'pod') && (
              <>
                <div className="flex items-center justify-between">
                  <div>
                    <h2 className="text-3xl font-black tracking-tighter">
                      {state.activeTab === 'pod' ? 'Pod Studio Mastery' : 'Estudio de Producción'}
                    </h2>
                    <p className="text-sm font-bold text-indigo-500/80 uppercase tracking-widest mt-1">
                      Neural Engine v3.1 {state.activeTab === 'pod' ? '• Professional Mode' : ''}
                    </p>
                  </div>
                  <div className="flex gap-2">
                    {THEMES.map(t => (
                      <button
                        key={t.name}
                        onClick={() => setState(prev => ({ ...prev, theme: t.classes }))}
                        className={`w-6 h-6 rounded-full bg-gradient-to-br ${t.classes} ${state.theme === t.classes ? 'ring-2 ring-indigo-500 ring-offset-2 dark:ring-offset-slate-900' : ''}`}
                      />
                    ))}
                  </div>
                </div>

                <Editor
                  text={text}
                  setText={setText}
                  onGenerate={handleGenerate}
                  isGenerating={isGenerating}
                  theme={state.theme}
                  mode={state.activeTab as 'vox' | 'pod'}
                />

                <AudioPlayer base64Data={lastAudio} />

                <div className="bg-white dark:bg-white/5 rounded-3xl p-6 border border-gray-100 dark:border-white/5 shadow-xl">
                  <div className="flex items-center justify-between mb-4">
                    <h4 className="text-xs font-black uppercase tracking-widest text-slate-400">Timeline de Producción</h4>
                    <span className="text-[10px] font-bold text-indigo-500 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-0.5 rounded-full">Auto-Duck Active</span>
                  </div>
                  <div className="h-24 w-full rounded-2xl bg-slate-50 dark:bg-black/20 border border-dashed border-slate-200 dark:border-white/10 relative overflow-hidden timeline-track">
                     {lastAudio && (
                       <div className="absolute inset-0 flex items-center justify-center opacity-30">
                         <div className="flex gap-1 items-center h-12">
                           {[...Array(60)].map((_, i) => (
                             <div key={i} className="w-1 bg-indigo-500 rounded-full" style={{ height: `${Math.random() * 100}%` }} />
                           ))}
                         </div>
                       </div>
                     )}
                     {!lastAudio && (
                       <div className="absolute inset-0 flex items-center justify-center">
                         <span className="text-[10px] font-bold text-slate-300 dark:text-slate-600 uppercase tracking-widest">Esperando Generación Master</span>
                       </div>
                     )}
                  </div>
                </div>
              </>
            )}

            {state.activeTab === 'history' && (
              <div className="flex flex-col gap-4 animate-in fade-in slide-in-from-bottom-4">
                <h2 className="text-2xl font-black">Librería de Master</h2>
                {state.history.length === 0 ? (
                  <div className="bg-white dark:bg-white/5 rounded-3xl p-10 text-center border-2 border-dashed border-slate-200 dark:border-white/10">
                    <p className="text-slate-400 font-bold">No hay archivos generados aún.</p>
                  </div>
                ) : (
                  state.history.map(item => (
                    <div key={item.id} className="bg-white dark:bg-white/5 p-5 rounded-3xl border border-gray-100 dark:border-white/5 flex items-center justify-between group hover:shadow-xl transition-all">
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl bg-gradient-to-br ${state.theme} flex items-center justify-center text-white`}>
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
                          </svg>
                        </div>
                        <div>
                          <p className="font-bold text-sm line-clamp-1">{item.text}</p>
                          <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mt-0.5">{item.voice} • {new Date(item.timestamp).toLocaleString()}</p>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            )}
          </div>

          <aside className="w-full lg:w-96 flex flex-col gap-8">
            <section className="bg-white dark:bg-slate-900/50 rounded-[2.5rem] p-8 shadow-2xl border border-white dark:border-white/5 backdrop-blur-xl">
              <h3 className="text-xl font-black mb-8 flex items-center justify-between">
                Console Master
                <span className="text-[10px] bg-indigo-50 dark:bg-indigo-900/30 text-indigo-500 px-3 py-1 rounded-full border border-indigo-100 dark:border-indigo-800">Neural Engine</span>
              </h3>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Región y Dialecto</label>
                  <select
                    value={selectedDialect}
                    onChange={(e) => setSelectedDialect(e.target.value)}
