                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Voz Seleccionada</label>
                  <div className="space-y-2 max-h-60 overflow-y-auto pr-2 scrollbar-thin">
                    {VOICE_DATA[state.language].voices.map(v => (
                      <div
                        key={v.id}
                        onClick={() => setSelectedVoice(v.id)}
                        className={`p-3 rounded-2xl border flex items-center justify-between cursor-pointer transition-all ${selectedVoice === v.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-white/5 border-transparent hover:border-indigo-200 dark:hover:border-indigo-800'}`}
                      >
                        <div className="flex items-center gap-3">
                           <div className={`w-8 h-8 rounded-xl flex items-center justify-center font-bold text-xs ${selectedVoice === v.id ? 'bg-white/20' : 'bg-indigo-500/10 text-indigo-500'}`}>
                             {v.gender[0]}
                           </div>
                           <span className="text-sm font-bold">{v.name}</span>
                        </div>
                        <VoicePreview voiceId={v.id} voiceName={v.name} theme={state.theme} />
                      </div>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Firma Emocional</label>
                  <select
                    value={selectedEmotion}
                    onChange={(e) => setSelectedEmotion(e.target.value)}
                    className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-white/10 focus:ring-2 ring-indigo-500 transition-all font-bold text-sm outline-none"
                  >
                    {EMOTIONAL_STATES.map(e => (
                      <option key={e} value={e}>{e}</option>
                    ))}
                  </select>
                </div>

                <div className="pt-6 space-y-6 border-t border-gray-100 dark:border-white/5">
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
