                 <span className="text-[8px] font-black uppercase tracking-widest px-2 py-0.5 bg-emerald-500 text-white rounded">Live</span>
               </h3>
               <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-2">
                    {AMBIENT_SOUNDS.slice(0, 8).map(s => (
                      <button key={s} className="px-3 py-2 rounded-xl bg-slate-50 dark:bg-white/5 text-[10px] font-bold text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 border border-transparent hover:border-indigo-100 dark:hover:border-indigo-800 transition-all">
                        {s}
                      </button>
                    ))}
                  </div>
               </div>
            </section>

            <section className="bg-gradient-to-br from-slate-900 to-indigo-950 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden group">
               <div className="relative z-10">
                 <div className="flex items-center justify-between mb-6">
                   <h3 className="text-lg font-black tracking-tight">Focus Master</h3>
                   <div className="flex gap-1">
