            >
              {isPlayingTour === 'ES' ? 'Reproduciendo...' : 'Demo Español 🇪🇸'}
            </button>
            <button 
              onClick={() => handleTour('EN')}
              disabled={!!isPlayingTour}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all shadow-sm ${isPlayingTour === 'EN' ? 'bg-indigo-600 text-white animate-pulse' : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-slate-200 dark:border-white/10 hover:border-indigo-500'}`}
            >
              {isPlayingTour === 'EN' ? 'Playing...' : 'English Demo 🇺🇸'}
            </button>
          </div>
        </div>
      )}

      {/* DuviPod Pro Core Features */}
      {mode === 'pod' && (
        <div className="flex flex-col gap-6 p-6 bg-gradient-to-br from-indigo-50/80 to-blue-50/80 dark:from-indigo-950/30 dark:to-slate-900/50 rounded-[2rem] border border-indigo-100 dark:border-indigo-900/50 animate-in fade-in slide-in-from-top-4 shadow-inner">
          <div className="flex flex-col lg:flex-row gap-4">
            <div className="flex-1 flex gap-2">
              <div className="relative flex-1">
                <input
                  type="text"
                  placeholder="YouTube, TikTok, FB Reels, IG, X..."
                  value={socialUrl}
                  onChange={(e) => setSocialUrl(e.target.value)}
                  className="w-full bg-white dark:bg-black/40 border border-slate-200 dark:border-white/10 p-4 pl-12 rounded-2xl text-sm font-medium focus:ring-2 ring-indigo-500 outline-none transition-all"
                />
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-500">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path d="M11 3a1 1 0 100 2h2.586l-6.293 6.293a1 1 0 101.414 1.414L15 6.414V9a1 1 0 102 0V4a1 1 0 00-1-1h-5z" />
                    <path d="M5 5a2 2 0 00-2 2v8a2 2 0 002 2h8a2 2 0 002-2v-3a1 1 0 10-2 0v3H5V7h3a1 1 0 000-2H5z" />
                  </svg>
                </div>
              </div>
              <button
                onClick={handleSocialImport}
                disabled={loading || !socialUrl}
                className="px-8 py-4 bg-indigo-600 text-white rounded-2xl text-xs font-black uppercase tracking-wider hover:bg-indigo-700 disabled:opacity-50 transition-all shadow-lg shadow-indigo-500/20 whitespace-nowrap"
              >
                {loading ? 'Procesando...' : 'Crear Podcast'}
