                  <span className="flex items-center gap-2 text-[10px] font-black bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-300 px-4 py-1.5 rounded-full uppercase border border-amber-200 dark:border-amber-800 animate-pulse shadow-sm">
