            {loading ? '...' : 'Traducción'}
          </button>
          <button
            onClick={handleFactCheck}
            disabled={loading}
            className="flex items-center gap-3 px-6 py-4 rounded-2xl bg-white dark:bg-emerald-500/10 border-2 border-emerald-500/20 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-500/20 transition-all text-sm font-black uppercase tracking-wider"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            {loading ? 'Verificando...' : 'Fact-Check'}
          </button>
        </div>

        <button
          onClick={onGenerate}
          disabled={isGenerating || !text}
          className={`px-12 py-5 rounded-[2rem] bg-gradient-to-r ${theme} text-white font-black uppercase tracking-[0.15em] shadow-[0_20px_40px_-15px_rgba(79,70,229,0.5)] hover:scale-[1.03] active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 flex items-center gap-4 text-base`}
        >
          {isGenerating ? (
            <>
              <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin" />
              Procesando Master...
            </>
          ) : (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168l4.2 2.8a1 1 0 010 1.664l-4.2 2.8A1 1 0 018 13.604V7.996a1 1 0 011.555-.832z" /></svg>
              Generar Producción Final
            </>
          )}
        </button>
      </div>
    </div>
  );
};

