import React, { useState, useEffect, useCallback } from 'react';
import { AppState, Language, HistoryItem } from './types';
import { VOICE_DATA, EMOTIONAL_STATES, THEMES } from './constants';
import TopBar from './components/TopBar';
import Editor from './components/Editor';
import Sidebar from './components/Sidebar';
import Stats from './components/Stats';
import { generateTTS, decode, decodeAudioData, factCheckAndRefine } from './services/gemini';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('duvivox_state_pro');
    return saved ? JSON.parse(saved) : {
      language: 'ES',
      theme: 'from-indigo-600 to-purple-700',
      isDarkMode: true,
      activeTab: 'vox',
      history: [],
      usage: []
    };
  });

  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState(VOICE_DATA[state.language].voices[0].id);
  const [selectedEmotion, setSelectedEmotion] = useState('Profesional');
  const [speed, setSpeed] = useState(1.0);
  const [pitch, setPitch] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [lastAudio, setLastAudio] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('duvivox_state_pro', JSON.stringify(state));
  }, [state]);

  const playSfx = () => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(500, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(1000, ctx.currentTime + 0.2);
    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start();
    osc.stop(ctx.currentTime + 0.3);
  };

  const handleGenerate = async () => {
    if (!text) return;
    setIsGenerating(true);
    try {
      const base64 = await generateTTS(text, selectedVoice, selectedEmotion, speed, pitch);
      if (base64) {
        setLastAudio(base64);
        const newItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          text: text.slice(0, 50) + '...',
          timestamp: Date.now(),
          audioData: base64,
          voice: selectedVoice,
          lang: state.language
        };
        setState(prev => ({...prev, history: [newItem, ...prev.history]}));

        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.start();
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="dark min-h-screen bg-[#020617] text-slate-100 font-sans">
      <TopBar state={state} setState={setState} />

      <div className="max-w-[1600px] mx-auto p-6 lg:p-10 flex flex-col lg:flex-row gap-8">
        {/* Main Content */}
        <div className="flex-1 order-2 lg:order-1 space-y-8">
          {state.activeTab === 'stats' ? (
            <Stats />
          ) : (
            <>
              <Editor
                text={text}
                setText={setText}
                onGenerate={handleGenerate}
                isGenerating={isGenerating}
                theme={state.theme}
                mode={state.activeTab === 'pod' ? 'pod' : 'vox'}
              />
              <AudioPlayer base64Data={lastAudio} />
            </>
          )}

          {/* Activity Feed in History */}
          {state.activeTab === 'history' && (
            <div className="space-y-4">
              {state.history.map(item => (
                <div key={item.id} className="bg-white/5 p-4 rounded-2xl flex items-center justify-between border border-white/5">
                   <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-indigo-500/20 rounded-lg flex items-center justify-center text-indigo-400">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                      </div>
                      <div>
                        <div className="font-bold truncate max-w-xs">{item.text}</div>
                        <div className="text-[10px] text-slate-500 uppercase">{item.voice} • {new Date(item.timestamp).toLocaleDateString()}</div>
                      </div>
                   </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="w-full lg:w-96 order-1 lg:order-2">
           <Sidebar activeTab={state.activeTab} setActiveTab={(t) => setState(prev => ({...prev, activeTab: t}))} playSfx={playSfx} />
        </div>
      </div>
    </div>
  );
};

