import { GoogleGenAI, Modality } from "@google/genai";

// Initialize AI client with process.env.API_KEY
const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Decodes base64 string to Uint8Array
export const decode = (base64: string) => {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

// Decodes raw PCM audio data into an AudioBuffer
export async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Translates text to target language
export const translateText = async (text: string, targetLanguage: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Traduce el siguiente texto a ${targetLanguage}: ${text}`,
  });
  return response.text;
};

// Performs fact check and refines text
export const factCheckAndRefine = async (text: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analiza la veracidad de este texto usando búsqueda en tiempo real y devuélvelo refinado: ${text}`,
    config: { tools: [{ googleSearch: {} }] },
  });
  return response.text;
};

// Generates podcast script from a social media URL
export const analyzeSocialUrl = async (url: string, duration: number) => {
  return generatePodcastScript(url, true, duration);
};

// Generates podcast script from a source (text or URL)
export const generatePodcastFromSource = async (source: string, type: string, duration: number) => {
  return generatePodcastScript(source, type === 'url', duration);
};

// Generates TTS audio data
export const generateTTS = async (text: string, voiceName: string, emotion: string = 'Neutral', speed: number = 1.0, pitch: number = 0) => {
  const ai = getAIClient();
  const prompt = `System: Eres un locutor profesional. 
    Voz: ${voiceName}. 
    Emoción: ${emotion}. 
    Velocidad: ${speed}x. 
    Tono: ${pitch}. 
    Texto: ${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

// Runs a fact check using google search tool
export const runFactCheck = async (text: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analiza la veracidad de este texto usando búsqueda en tiempo real: ${text}`,
    config: { tools: [{ googleSearch: {} }] },
  });
  return response.text;
};

// Generates a podcast script based on source and duration
export const generatePodcastScript = async (source: string, isUrl: boolean, duration: number) => {
  const ai = getAIClient();
  const needsResearch = duration > 120;
  const prompt = `Crea un guion de podcast de aproximadamente ${duration} segundos basado en: ${source}. 
    ${needsResearch ? 'Utiliza Google Search para investigar el trasfondo, historia y detalles curiosos del tema para hacerlo más profundo.' : ''}
    Incluye marcas de entonación como [Risa], [Pausa 2s] y [stress]palabra[/stress].`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: needsResearch ? { tools: [{ googleSearch: {} }] } : {},
  });
  return response.text;
};

