    ${needsResearch ? 'Utiliza Google Search para investigar el trasfondo, historia y detalles curiosos del tema para hacerlo más profundo.' : ''}
    Incluye marcas de entonación como [Risa], [Pausa 2s] y [stress]palabra[/stress].`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: needsResearch ? { tools: [{ googleSearch: {} }] } : {},
  });
  return response.text;
};

export const generatePodcastFromSource = async (source: string, type: string, duration: number) => {
  const ai = getAIClient();
  const needsResearch = duration > 120;
  const prompt = `Crea un guion de podcast de aproximadamente ${duration} segundos basado en este contenido: ${source}. 
    ${needsResearch ? 'Utiliza Google Search para investigar el trasfondo, historia y detalles curiosos del tema para hacerlo más profundo.' : ''}
    Incluye marcas de entonación como [Risa], [Pausa 2s] y [stress]palabra[/stress].`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: needsResearch ? { tools: [{ googleSearch: {} }] } : {},
  });
  return response.text;
};

