import React, { useState } from 'react';
import { translateText, factCheckAndRefine, analyzeSocialUrl, generatePodcastFromSource, generateTTS, decode, decodeAudioData } from '../services/gemini';
import { GESTURES } from '../constants';

interface EditorProps {
  text: string;
  setText: (text: string) => void;
  onGenerate: () => void;
  isGenerating: boolean;
  theme: string;
  mode: 'vox' | 'pod';
}

const Editor: React.FC<EditorProps> = ({ text, setText, onGenerate, isGenerating, theme, mode }) => {
  const [loading, setLoading] = useState(false);
  const [socialUrl, setSocialUrl] = useState('');
  const [podcastDuration, setPodcastDuration] = useState(120);
  const [isPlayingTour, setIsPlayingTour] = useState<'ES' | 'EN' | null>(null);

  const insertTag = (tag: string) => {
    setText(text + ` [${tag}] `);
  };

  const handleTour = async (lang: 'ES' | 'EN') => {
    if (isPlayingTour) return;
    setIsPlayingTour(lang);
    setLoading(true);
    try {
      const script = lang === 'ES' 
        ? "Bienvenido a DuviPod Studio Pro. Nuestra plataforma transforma contenido de redes sociales y documentos en podcasts profesionales de hasta noventa minutos. Con nuestra inteligencia artificial, investigamos automáticamente en la web para enriquecer tus guiones con datos históricos y contexto real, asegurando una producción profunda y educativa. Experimenta el futuro de la creación sonora con DuviVox."
        : "Welcome to DuviPod Studio Pro. Our platform transforms social media content and documents into professional podcasts up to ninety minutes long. With our artificial intelligence, we automatically research the web to enrich your scripts with historical data and real context, ensuring a deep and educational production. Experience the future of sound creation with DuviVox.";

      const voiceId = lang === 'ES' ? 'Zephyr' : 'Kore'; 
      const base64 = await generateTTS(script, voiceId, 'Profesional');

      if (base64) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.onended = () => setIsPlayingTour(null);
        source.start();
      } else {
        setIsPlayingTour(null);
      }
    } catch (err) {
      console.error("Tour failed", err);
      setIsPlayingTour(null);
    } finally {
      setLoading(false);
    }
  };

  const handleTranslate = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const translated = await translateText(text, 'English');
      if (translated) setText(translated);
    } finally {
      setLoading(false);
    }
  };

  const handleFactCheck = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const refined = await factCheckAndRefine(text);
      if (refined) setText(refined);
    } finally {
      setLoading(false);
    }
  };

  const handleSocialImport = async () => {
    if (!socialUrl) return;
    setLoading(true);
    try {
      const script = await analyzeSocialUrl(socialUrl, podcastDuration);
      if (script) {
        setText(script);
        setSocialUrl('');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setLoading(true);
    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const content = e.target?.result as string;
        const script = await generatePodcastFromSource(content, 'text', podcastDuration);
        if (script) setText(script);
      };
      reader.readAsText(file);
    } finally {
      setLoading(false);
    }
  };

  const formatDuration = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    if (h > 0) return `${h}h ${m}m ${s}s`;
    return `${m}m ${s}s`;
  };

  return (
    <div className="bg-white dark:bg-slate-900/50 rounded-[2.5rem] p-8 shadow-2xl border border-white dark:border-white/5 flex flex-col gap-6 backdrop-blur-xl transition-all duration-500">
      {mode === 'pod' && (
        <div className="flex flex-col gap-4 p-4 bg-indigo-500/5 rounded-3xl border border-indigo-500/20">
          <div className="flex justify-between items-center">
            <h5 className="text-[10px] font-black uppercase text-indigo-400 tracking-widest">Demos de Presentación</h5>
            <div className="flex gap-2">
              <button onClick={() => handleTour('ES')} disabled={!!isPlayingTour} className="px-3 py-1.5 rounded-lg bg-white/5 text-[10px] font-bold hover:bg-white/10 transition-colors">ES 🇪🇸</button>
              <button onClick={() => handleTour('EN')} disabled={!!isPlayingTour} className="px-3 py-1.5 rounded-lg bg-white/5 text-[10px] font-bold hover:bg-white/10 transition-colors">EN 🇺🇸</button>
            </div>
          </div>

          <div className="flex flex-col lg:flex-row gap-4">
            <div className="flex-1 flex gap-2">
              <input
                type="text"
                placeholder="Enlace de Red Social (YT, TikTok...)"
                value={socialUrl}
                onChange={(e) => setSocialUrl(e.target.value)}
                className="flex-1 bg-white/5 border border-white/10 p-4 rounded-2xl text-sm focus:ring-1 ring-indigo-500 outline-none"
              />
              <button onClick={handleSocialImport} disabled={loading} className="px-6 py-4 bg-indigo-600 rounded-2xl text-xs font-black uppercase tracking-widest">
                Importar
              </button>
            </div>
            <label className="flex items-center justify-center gap-2 px-6 py-4 bg-white/5 rounded-2xl border border-dashed border-white/20 text-xs font-bold cursor-pointer hover:bg-white/10">
              📁 PDF/TXT
              <input type="file" className="hidden" accept=".pdf,.txt" onChange={handleFileUpload} />
            </label>
          </div>

          <div className="px-2">
            <div className="flex justify-between text-[10px] font-black text-slate-500 uppercase mb-2">
              <span>Duración: {formatDuration(podcastDuration)}</span>
              {podcastDuration > 120 && <span className="text-emerald-500">Enriquecimiento Activo ✨</span>}
            </div>
            <input type="range" min="30" max="5400" step="30" value={podcastDuration} onChange={(e) => setPodcastDuration(parseInt(e.target.value))} className="w-full custom-range" />
          </div>
        </div>
      )}

      <div className="flex flex-col gap-3">
        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
          {GESTURES.map(g => (
            <button key={g.tag} onClick={() => insertTag(g.tag)} className="px-3 py-2 rounded-xl bg-white/5 text-[10px] font-bold hover:bg-indigo-600 transition-all border border-white/5 whitespace-nowrap">
              {g.label}
            </button>
          ))}
          <button onClick={() => insertTag('stress')} className="px-3 py-2 rounded-xl bg-indigo-600/30 text-indigo-400 text-[10px] font-black border border-indigo-500/30">ENFASIS</button>
        </div>
      </div>

      <textarea
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Escribe o importa contenido..."
        className="w-full h-64 bg-transparent resize-none text-lg leading-relaxed focus:outline-none placeholder-slate-700 font-medium"
      />

      <div className="flex flex-wrap items-center justify-between pt-6 border-t border-white/5 gap-4">
        <div className="flex gap-2">
          <button onClick={handleTranslate} className="px-4 py-3 rounded-xl bg-white/5 border border-white/5 text-[10px] font-black uppercase hover:bg-white/10">Traducción</button>
          <button onClick={handleFactCheck} className="px-4 py-3 rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-500 text-[10px] font-black uppercase hover:bg-emerald-500/20">Fact-Check</button>
        </div>

        <button
          onClick={onGenerate}
          disabled={isGenerating || !text}
          className={`px-10 py-4 rounded-2xl bg-gradient-to-r ${theme} text-white font-black uppercase tracking-widest shadow-lg hover:scale-105 transition-all disabled:opacity-50`}
        >
          {isGenerating ? 'Generando...' : 'Generar Audio'}
        </button>
      </div>
    </div>
  );
};

export default Editor;

