import { GoogleGenAI, Modality } from "@google/genai";

// Initialize the GoogleGenAI client with the API key from environment variables.
const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Decodes a base64 string into a Uint8Array of bytes.
export const decode = (base64: string) => {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

// Decodes raw PCM audio data into an AudioBuffer for playback.
export async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Generates Text-to-Speech audio using the specialized gemini-2.5-flash-preview-tts model.
export const generateTTS = async (text: string, voiceName: string, emotion: string = 'Neutral', speed: number = 1.0, pitch: number = 0) => {
  const ai = getAIClient();
  const prompt = `Actúa como un locutor profesional. 
    Voz configurada: ${voiceName}. 
    Emoción solicitada: ${emotion}. 
    Ritmo: ${speed}x. 
    Tono: ${pitch}. 
    Texto a locutar: ${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

// Performs fact-checking and enrichment using Google Search grounding.
export const runFactCheck = async (text: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analiza la veracidad histórica y actual de la siguiente información. Si detectas errores, corrígelos y explica por qué. Utiliza fuentes fiables vía Google Search. Texto: "${text}"`,
    config: { tools: [{ googleSearch: {} }] },
  });

  // Extract and list URLs from grounding metadata as required by the guidelines.
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.filter(chunk => chunk.web && chunk.web.uri)
    ?.map(chunk => chunk.web!.uri);

  if (sources && sources.length > 0) {
    const uniqueSources = Array.from(new Set(sources));
    return `${response.text}\n\nFuentes consultadas:\n${uniqueSources.join('\n')}`;
  }

  return response.text;
};

// Fix for missing export reported in Editor.tsx.
export const analyzeSocialUrl = async (url: string, duration: number) => {
  return generatePodcastFromSource(url, 'url', duration);
};

// Generates a podcast script based on a source, using Google Search for long-form content.
export const generatePodcastFromSource = async (source: string, type: 'url' | 'text' | 'pdf', duration: number) => {
  const ai = getAIClient();
  const isLong = duration > 120;

  const prompt = `Genera un guion de podcast profesional de aproximadamente ${duration} segundos basado en el siguiente ${type === 'url' ? 'enlace' : 'contenido'}: ${source}.

  ${isLong ? 'IMPORTANTE: Dado que el podcast es extenso, utiliza Google Search para investigar a fondo sobre el tema, encontrar datos curiosos, contexto histórico y ramificaciones interesantes para que el contenido sea rico y educativo.' : 'Resume los puntos clave de forma directa.'}

  Escribe el guion integrando etiquetas como [Risa], [Pausa 2s] y rodeando palabras clave con [stress]palabra[/stress] para dar énfasis. El tono debe ser de un podcaster experto.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: isLong ? { tools: [{ googleSearch: {} }] } : {},
  });

  let resultText = response.text || '';

  // Extract and list URLs from grounding metadata if Google Search was active.
  if (isLong) {
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter(chunk => chunk.web && chunk.web.uri)
      ?.map(chunk => chunk.web!.uri);

    if (sources && sources.length > 0) {
       const uniqueSources = Array.from(new Set(sources));
       resultText += `\n\nFuentes de investigación:\n${uniqueSources.join('\n')}`;
    }
  }

  return resultText;
};

// Translates text to a target language.
export const translateText = async (text: string, targetLanguage: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Traduce fielmente el siguiente texto al ${targetLanguage}, manteniendo el tono original: ${text}`,
  });
  return response.text;
};

import React, { useState, useEffect } from 'react';
import { AppState, Language, HistoryItem } from './types';
import { VOICE_DATA, THEMES } from './constants';
import TopBar from './components/TopBar';
import Editor from './components/Editor';
import Sidebar from './components/Sidebar';
import Stats from './components/Stats';
import AudioPlayer from './components/AudioPlayer';
import Onboarding from './components/Onboarding';
import { generateTTS, decode, decodeAudioData } from './services/gemini';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('duvivox_pro_v2');
    return saved ? JSON.parse(saved) : {
      language: 'ES',
      theme: 'from-indigo-600 to-purple-700',
      activeTab: 'vox',
      history: [],
      showOnboarding: true
    };
  });

  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState(VOICE_DATA[state.language].voices[0].id);
  const [isGenerating, setIsGenerating] = useState(false);
  const [lastAudio, setLastAudio] = useState<string | null>(null);

  // Pomodoro State lifted from Sidebar
  const [pomodoro, setPomodoro] = useState(25 * 60);
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  useEffect(() => {
    localStorage.setItem('duvivox_pro_v2', JSON.stringify(state));
  }, [state]);

  // Pomodoro logic
  useEffect(() => {
    let timer: any;
    if (isTimerRunning && pomodoro > 0) {
      timer = setInterval(() => setPomodoro(p => p - 1), 1000);
    } else if (pomodoro === 0) {
      setIsTimerRunning(false);
      // Play a subtle notification sound if possible
      playSfx();
      alert('¡Tiempo de descanso!');
    }
    return () => clearInterval(timer);
  }, [isTimerRunning, pomodoro]);

  const playSfx = () => {
    try {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(500, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.15);
      gain.gain.setValueAtTime(0.04, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + 0.25);
    } catch (e) {
      console.log('Audio disabled');
    }
  };

  const handleGenerate = async () => {
    if (!text) return;
    setIsGenerating(true);
    try {
      const base64 = await generateTTS(text, selectedVoice, 'Profesional');
      if (base64) {
        setLastAudio(base64);
        const newItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          text: text.slice(0, 50) + '...',
          timestamp: Date.now(),
          audioData: base64,
          voice: selectedVoice,
          lang: state.language
        };
        setState(prev => ({...prev, history: [newItem, ...prev.history]}));

        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.start();
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-100 font-sans selection:bg-indigo-500/40">
      <TopBar 
        state={state} 
        setState={setState} 
        pomodoro={pomodoro} 
        setPomodoro={setPomodoro}
        isTimerRunning={isTimerRunning}
        setIsTimerRunning={setIsTimerRunning}
      />

      {state.showOnboarding && (
        <Onboarding 
          theme={state.theme} 
          onClose={() => setState(s => ({...s, showOnboarding: false}))} 
        />
      )}

      <main className="max-w-[1600px] mx-auto p-6 lg:p-10">
        <div className="flex flex-col lg:flex-row gap-10">

          {/* Main Area */}
          <div className="flex-1 order-2 lg:order-1 space-y-8">
            {state.activeTab === 'stats' ? (
              <div className="space-y-6">
                <h2 className="text-3xl font-black tracking-tight">Analytics Dashboard</h2>
                <Stats />
              </div>
            ) : state.activeTab === 'history' ? (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
                <h2 className="text-3xl font-black tracking-tight">Mi Librería</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {state.history.length > 0 ? state.history.map(item => (
                    <div key={item.id} className="bg-white/5 p-6 rounded-[2rem] flex items-center justify-between border border-white/5 hover:border-white/20 transition-all group">
                       <div className="flex items-center gap-4 overflow-hidden">
                          <div className="w-12 h-12 bg-indigo-500/10 rounded-2xl flex-shrink-0 flex items-center justify-center text-indigo-400 group-hover:scale-110 transition-transform">
                            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168l4.2 2.8a1 1 0 010 1.664l-4.2 2.8A1 1 0 018 13.604V7.996a1 1 0 011.555-.832z" clipRule="evenodd"></path></svg>
                          </div>
                          <div className="truncate">
                            <div className="font-bold truncate text-slate-200">{item.text}</div>
                            <div className="text-[10px] text-slate-500 uppercase tracking-widest">{item.voice} • {new Date(item.timestamp).toLocaleDateString()}</div>
                          </div>
                       </div>
                    </div>
                  )) : (
                    <div className="col-span-2 py-20 text-center text-slate-600 font-bold uppercase tracking-widest italic">
                      No hay registros todavía...
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <>
                <div className="flex items-center justify-between mb-2">
                   <h2 className="text-3xl font-black tracking-tight uppercase">
                    {state.activeTab === 'pod' ? 'Podcasting Studio' : 'Vocal Interface'}
                   </h2>
                   <div className="flex gap-2">
                      <span className="w-2 h-2 rounded-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.5)]"></span>
                      <span className="w-2 h-2 rounded-full bg-slate-700"></span>
                   </div>
                </div>
                <Editor
                  text={text}
                  setText={setText}
                  onGenerate={handleGenerate}
                  isGenerating={isGenerating}
                  theme={state.theme}
                  mode={state.activeTab === 'pod' ? 'pod' : 'vox'}
                />
                <AudioPlayer base64Data={lastAudio} />
              </>
            )}
          </div>

          {/* Sidebar Area */}
          <aside className="w-full lg:w-96 order-1 lg:order-2">
             <Sidebar 
                activeTab={state.activeTab} 
                setActiveTab={(t) => setState(prev => ({...prev, activeTab: t}))} 
                playSfx={playSfx}
                language={state.language}
                selectedVoice={selectedVoice}
                onVoiceChange={setSelectedVoice}
                theme={state.theme}
             />
          </aside>
        </div>
      </main>
    </div>
  );
};

export default App;

