            ) : (
              <div className="animate-in fade-in duration-700">
                <div className="flex items-center justify-between mb-4">
                   <h2 className="text-3xl font-black tracking-tight uppercase italic text-slate-100">
                    {state.activeTab === 'pod' ? 'Podcasting Studio' : 'Vocal AI Interface'}
                   </h2>
                   <div className="flex gap-2">
                      <span className="w-2 h-2 rounded-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.6)] animate-pulse"></span>
                      <span className="w-2 h-2 rounded-full bg-slate-800"></span>
                   </div>
                </div>
                <Editor
                  text={text}
                  setText={setText}
                  onGenerate={handleGenerate}
                  isGenerating={isGenerating}
                  theme={state.theme}
                  mode={state.activeTab === 'pod' ? 'pod' : 'vox'}
                />
                <AudioPlayer base64Data={lastAudio} />
              </div>
            )}
          </div>

          <aside className="w-full lg:w-96 order-1 lg:order-2 flex-shrink-0">
             <Sidebar 
                activeTab={state.activeTab} 
                setActiveTab={(t) => setState(prev => ({...prev, activeTab: t}))} 
                playSfx={playSfx}
                language={state.language}
                selectedVoice={selectedVoice}
                onVoiceChange={setSelectedVoice}
                theme={state.theme}
             />
          </aside>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AppState, HistoryItem } from './types';
import { VOICE_DATA } from './constants';
import TopBar from './components/TopBar';
import Editor from './components/Editor';
import Sidebar from './components/Sidebar';
import Stats from './components/Stats';
import AudioPlayer from './components/AudioPlayer';
import Onboarding from './components/Onboarding';
import { generateTTS, decode, decodeAudioData } from './services/gemini';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    try {
      const saved = localStorage.getItem('duvivox_pro_v2');
      if (saved) {
        const parsed = JSON.parse(saved);
        // Basic sanitization of history to ensure strings
        if (parsed.history) {
          parsed.history = parsed.history.map((item: any) => ({
            ...item,
            text: String(item.text || ""),
            voice: String(item.voice || ""),
            lang: String(item.lang || "")
          }));
        }
        return parsed;
      }
    } catch (e) {
      console.error("Error cargando almacenamiento:", e);
    }
    return {
      language: 'ES',
      theme: 'from-indigo-600 to-purple-700',
      activeTab: 'vox',
      history: [],
      showOnboarding: true
    };
  });

  const [text, setText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState(() => {
    const langData = VOICE_DATA[state.language] || VOICE_DATA['ES'];
    return langData.voices[0]?.id || 'Zephyr';
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [lastAudio, setLastAudio] = useState<string | null>(null);

  // Pomodoro State
  const [pomodoro, setPomodoro] = useState(25 * 60);
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  useEffect(() => {
    localStorage.setItem('duvivox_pro_v2', JSON.stringify(state));
  }, [state]);

  useEffect(() => {
    let timer: any;
    if (isTimerRunning && pomodoro > 0) {
      timer = setInterval(() => setPomodoro(p => p - 1), 1000);
    } else if (pomodoro === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      playSfx();
      alert('¡Sessión completada!');
    }
    return () => clearInterval(timer);
  }, [isTimerRunning, pomodoro]);

  const playSfx = () => {
    try {
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContextClass) return;
      const ctx = new AudioContextClass();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(500, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.15);
      gain.gain.setValueAtTime(0.04, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + 0.25);
    } catch (e) {
      console.debug('SFX disabled');
    }
  };

  const handleGenerate = async () => {
    if (!text.trim()) return;
    setIsGenerating(true);
    try {
      const base64 = await generateTTS(text, selectedVoice, 'Profesional');
      if (base64) {
        setLastAudio(base64);
        const newItem: HistoryItem = {
          id: Math.random().toString(36).substr(2, 9),
          text: String(text.slice(0, 60).trim() + (text.length > 60 ? '...' : '')),
          timestamp: Date.now(),
          audioData: base64,
          voice: String(selectedVoice),
          lang: String(state.language)
        };
        setState(prev => ({...prev, history: [newItem, ...prev.history]}));

        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioContext = new AudioContextClass({ sampleRate: 24000 });
        const buffer = await decodeAudioData(decode(base64), audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.start();
      }
    } catch (e) {
      console.error("Error en generación:", e);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-100 font-sans selection:bg-indigo-500/40">
      <TopBar 
        state={state} 
        setState={setState} 
        pomodoro={pomodoro} 
        setPomodoro={setPomodoro}
        isTimerRunning={isTimerRunning}
        setIsTimerRunning={setIsTimerRunning}
      />

      {state.showOnboarding && (
        <Onboarding 
          theme={state.theme} 
          onClose={() => setState(s => ({...s, showOnboarding: false}))} 
        />
      )}

      <main className="max-w-[1600px] mx-auto p-4 sm:p-6 lg:p-10">
        <div className="flex flex-col lg:flex-row gap-8 lg:gap-12">

          <div className="flex-1 order-2 lg:order-1 space-y-8 min-w-0">
            {state.activeTab === 'stats' ? (
              <div className="space-y-6">
                <h2 className="text-3xl font-black tracking-tight uppercase italic text-slate-100">Analíticas de Usuario</h2>
                <Stats />
              </div>
            ) : state.activeTab === 'history' ? (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <h2 className="text-3xl font-black tracking-tight uppercase italic text-slate-100">Librería de Audios</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {state.history && state.history.length > 0 ? state.history.map(item => (
                    <div key={item.id} className="bg-white/5 p-6 rounded-[2rem] border border-white/5 hover:border-white/20 transition-all group flex items-center justify-between">
                       <div className="flex items-center gap-4 overflow-hidden">
                          <div className="w-12 h-12 bg-indigo-500/10 rounded-2xl flex-shrink-0 flex items-center justify-center text-indigo-400">
                            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168l4.2 2.8a1 1 0 010 1.664l-4.2 2.8A1 1 0 018 13.604V7.996a1 1 0 011.555-.832z"></path></svg>
                          </div>
                          <div className="truncate">
                            <div className="font-bold truncate text-slate-200">{String(item.text)}</div>
                            <div className="text-[10px] text-slate-500 uppercase tracking-widest">{String(item.voice)} • {new Date(item.timestamp).toLocaleDateString()}</div>
                          </div>
                       </div>
                    </div>
                  )) : (
                    <div className="col-span-full py-24 text-center text-slate-600 font-bold uppercase tracking-widest italic border-2 border-dashed border-white/5 rounded-[3rem]">
                      No hay registros en la base de datos
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className="animate-in fade-in duration-700">
                <div className="flex items-center justify-between mb-4">
                   <h2 className="text-3xl font-black tracking-tight uppercase italic text-slate-100">
                    {state.activeTab === 'pod' ? 'Podcasting Studio' : 'Vocal AI Interface'}
                   </h2>
                   <div className="flex gap-2">
                      <span className="w-2 h-2 rounded-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.6)] animate-pulse"></span>
                      <span className="w-2 h-2 rounded-full bg-slate-800"></span>
                   </div>
                </div>
                <Editor
                  text={text}
                  setText={setText}
                  onGenerate={handleGenerate}
                  isGenerating={isGenerating}
                  theme={state.theme}
                  mode={state.activeTab === 'pod' ? 'pod' : 'vox'}
                />
                <AudioPlayer base64Data={lastAudio} />
              </div>
            )}
          </div>

          <aside className="w-full lg:w-96 order-1 lg:order-2 flex-shrink-0">
             <Sidebar 
                activeTab={state.activeTab} 
                setActiveTab={(t) => setState(prev => ({...prev, activeTab: t}))} 
                playSfx={playSfx}
                language={state.language}
                selectedVoice={selectedVoice}
                onVoiceChange={setSelectedVoice}
                theme={state.theme}
             />
          </aside>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { translateText, runFactCheck, analyzeSocialUrl, generatePodcastFromSource } from '../services/gemini';
import { GESTURES } from '../constants';

interface EditorProps {
  text: string;
  setText: (text: string) => void;
  onGenerate: () => void;
  isGenerating: boolean;
  theme: string;
  mode: 'vox' | 'pod';
}

const Editor: React.FC<EditorProps> = ({ text, setText, onGenerate, isGenerating, theme, mode }) => {
  const [loading, setLoading] = useState(false);
  const [socialUrl, setSocialUrl] = useState('');
  const [podcastDuration, setPodcastDuration] = useState(120);

  const insertTag = (tag: string) => {
    setText(text + ` [${tag}] `);
  };

  const handleTranslate = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const translated = await translateText(text, 'English');
      if (translated) setText(translated);
    } finally {
      setLoading(false);
    }
  };

  const handleFactCheck = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const refined = await runFactCheck(text);
      if (refined) setText(refined);
    } finally {
      setLoading(false);
    }
  };

  const handleSocialImport = async () => {
    if (!socialUrl) return;
    setLoading(true);
    try {
      const script = await analyzeSocialUrl(socialUrl, podcastDuration);
      if (script) {
        setText(script);
        setSocialUrl('');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setLoading(true);
    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const content = e.target?.result as string;
        const script = await generatePodcastFromSource(content, 'text', podcastDuration);
        if (script) setText(script);
      };
      reader.readAsText(file);
    } finally {
      setLoading(false);
    }
  };

  const formatDuration = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    if (h > 0) return `${h}h ${m}m ${s}s`;
    return `${m}m ${s}s`;
  };

  return (
    <div className="bg-white/5 border border-white/10 rounded-[2.5rem] p-8 shadow-2xl flex flex-col gap-6 backdrop-blur-xl animate-slide-up">
      {/* DuviPod Pro Intelligence Panel */}
      {mode === 'pod' && (
        <div className="flex flex-col gap-4 p-5 bg-indigo-500/5 rounded-[2rem] border border-indigo-500/20">
          <div className="flex justify-between items-center mb-1">
            <h5 className="text-[10px] font-black uppercase text-indigo-400 tracking-widest flex items-center gap-2">
              <span className="w-2 h-2 bg-indigo-500 rounded-full animate-ping" />
              DuviPod Intelligence Tools
            </h5>
          </div>

          <div className="flex flex-col lg:flex-row gap-4">
            <div className="flex-1 flex gap-2">
              <input
                type="text"
                placeholder="Pega link de Video o Artículo..."
                value={socialUrl}
                onChange={(e) => setSocialUrl(e.target.value)}
                className="flex-1 bg-black/40 border border-white/5 p-4 rounded-2xl text-sm font-medium focus:ring-1 ring-indigo-500 outline-none placeholder:text-slate-600"
              />
              <button 
                onClick={handleSocialImport} 
                disabled={loading || !socialUrl} 
                className="px-6 py-4 bg-indigo-600 rounded-2xl text-xs font-black uppercase tracking-widest hover:scale-105 transition-transform disabled:opacity-50"
              >
                {loading ? '...' : 'Procesar'}
              </button>
            </div>
            <label className="flex items-center justify-center gap-2 px-6 py-4 bg-white/5 rounded-2xl border border-dashed border-white/10 text-xs font-bold cursor-pointer hover:bg-white/10 transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
              PDF / TXT
              <input type="file" className="hidden" accept=".pdf,.txt" onChange={handleFileUpload} />
            </label>
          </div>

          <div className="mt-2 px-2">
            <div className="flex justify-between text-[11px] font-black text-slate-400 uppercase mb-3">
              <span className="flex items-center gap-2">
                Duración Estimada: <span className="text-white">{formatDuration(podcastDuration)}</span>
              </span>
              {podcastDuration > 120 ? (
                <span className="text-indigo-400 flex items-center gap-1">
                  <svg className="w-3 h-3 animate-spin" viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83" strokeWidth="2" strokeLinecap="round"/></svg>
                  Búsqueda Enriquecida Activa
                </span>
              ) : <span className="text-slate-600 italic">Modo Rápido</span>}
            </div>
            <input 
              type="range" 
              min="30" 
              max="5400" 
              step="30" 
              value={podcastDuration} 
              onChange={(e) => setPodcastDuration(parseInt(e.target.value))} 
              className="w-full custom-range" 
            />
          </div>
        </div>
      )}

      {/* Editor Annotations */}
      <div className="flex flex-col gap-3">
        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar border-b border-white/5">
          <span className="text-[10px] font-black text-slate-500 uppercase flex items-center pr-2">Anotaciones</span>
          {GESTURES.map(g => (
            <button key={g.tag} onClick={() => insertTag(g.tag)} className="px-3 py-1.5 rounded-xl bg-white/5 text-[10px] font-bold hover:bg-indigo-600 transition-all border border-white/5 whitespace-nowrap">
              {g.label}
            </button>
          ))}
          <button onClick={() => insertTag('stress')} className="px-3 py-1.5 rounded-xl bg-indigo-600/30 text-indigo-400 text-[10px] font-black border border-indigo-500/30">ÉNFASIS</button>
        </div>
      </div>

      <div className="relative">
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Comienza a escribir o importa contenido para procesar..."
          className="w-full h-80 bg-transparent resize-none text-lg leading-relaxed focus:outline-none placeholder-slate-700 font-medium"
        />
        {loading && (
          <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px] rounded-2xl flex items-center justify-center z-10">
            <div className="flex flex-col items-center gap-3">
              <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin" />
              <span className="text-xs font-black uppercase tracking-widest text-indigo-400">Procesando Inteligencia...</span>
            </div>
          </div>
        )}
      </div>

      <div className="flex flex-wrap items-center justify-between pt-6 border-t border-white/5 gap-4">
        <div className="flex gap-2">
          <button 
            onClick={handleTranslate} 
            disabled={loading || !text}
            className="px-5 py-3 rounded-2xl bg-white/5 border border-white/5 text-[10px] font-black uppercase hover:bg-white/10 tracking-widest disabled:opacity-50"
          >
            Traducir EN
          </button>
          <button 
            onClick={handleFactCheck} 
            disabled={loading || !text}
            className="px-5 py-3 rounded-2xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-500 text-[10px] font-black uppercase hover:bg-emerald-500/20 tracking-widest disabled:opacity-50"
          >
            Fact-Check
          </button>
        </div>

        <button
          onClick={onGenerate}
          disabled={isGenerating || !text || loading}
          className={`px-10 py-5 rounded-[2rem] bg-gradient-to-r ${theme} text-white font-black uppercase tracking-widest shadow-lg hover:scale-105 transition-all disabled:opacity-50 btn-glow`}
        >
          {isGenerating ? 'Generando Master...' : 'Generar Audio'}
        </button>
      </div>
    </div>
  );
};

export default Editor;
